using namespace adsk::core;
using namespace adsk::fusion;

Ptr ui;

extern "C" XI_EXPORT bool run(const char* context)
{
    Ptr app = Application::get();
    if (!app)
        return false;

    ui = app->userInterface();
    if (!ui)
        return false;


    // Get active design
    Ptr product = app->activeProduct();
    if (!product)
        return false;

    Ptr design = product;
    if (!design)
        return false;

    // Get root component in this design
    Ptr rootComp = design->rootComponent();
    if (!rootComp)
        return false;

    // Get hem features
    Ptr features = rootComp->features();
    if (!features)
        return false;

    Ptr hemFeatures = features->hemFeatures();
    if (!hemFeatures)
        return false;

    Ptr bodies = rootComp->bRepBodies();

    Ptr body = bodies->item(0);

    Ptr edges = body->edges();

    // Create an open hem
    Ptr gap = ValueInput::createByReal(0.2);

    Ptr length = ValueInput::createByReal(2.0);

    Ptr openHemFeatureInput = hemFeatures->createHemFeatureInput();

    Ptr edge = edges->item(0);

    bool isFlipped = false;

    BendPositionTypes bendPositionType = BendPositionTypes::StartEdgeBendPositionType;


    // Create the feature
    Ptr openHemFeature = hemFeatures->add(openHemFeatureInput);

    // Create a rolled hem
    Ptr radius = ValueInput::createByReal(0.3);

    Ptr angle = ValueInput::createByReal(4.5);

    Ptr rolledHemFeatureInput = hemFeatures->createHemFeatureInput();

    Ptr edge = edges->item(5);

    // Use same bend position and flip options as previous hem

    // Create the feature
    Ptr rolledHemFeature = hemFeatures->add(rolledHemFeatureInput);


    return true;
}
